// src/components/Quiz.js
import React, {useEffect, useState, useRef, useMemo} from "react";

/*
Fixed:
- Options no longer reshuffle every second because of useMemo
*/

const STORAGE_KEY = "scan2learn_quiz_state_v1";

function generateMCQ(answer){
  if(!answer || answer.trim()==="") return [];
  const base = answer.trim();
  const wrong1 = base.length>4 ? base.slice(0,Math.max(1,Math.floor(base.length/2))) : base + "X";
  const wrong2 = base + " related";
  const candidates = [base, wrong1, wrong2];
  const uniq = Array.from(new Set(candidates));

  // shuffle once
  for(let i=uniq.length-1;i>0;i--){
    const j = Math.floor(Math.random() * (i+1));
    [uniq[i],uniq[j]]=[uniq[j],uniq[i]];
  }
  return uniq;
}

export default function Quiz({items}) {

  const norm = items.map(it => ({ question: it.question||it, answer: it.answer||"" }));

  const [pageIndex,setPageIndex] = useState(0);
  const [selections,setSelections] = useState({});
  const [checked,setChecked] = useState({});
  const [submitted,setSubmitted] = useState(false);
  const [timeLeft,setTimeLeft] = useState(30);
  const [running,setRunning] = useState(true);
  const [perQuestionTime,setPerQuestionTime] = useState(30);
  const [itemsPerPage,setItemsPerPage] = useState(1);
  const [animateKey,setAnimateKey] = useState(0);
  const timerRef = useRef(null);

  // Load saved progress
  useEffect(()=>{
    try{
      const raw = localStorage.getItem(STORAGE_KEY);
      if(raw){
        const data = JSON.parse(raw);
        if(data?.total === norm.length){
          setPageIndex(data.pageIndex || 0);
          setSelections(data.selections || {});
          setChecked(data.checked || {});
          setSubmitted(data.submitted || false);
          setTimeLeft(data.timeLeft || 30);
        }
      }
    }catch(err){}
  },[]);

  useEffect(()=>{
    const st = {total: norm.length, pageIndex, selections, checked, submitted, timeLeft};
    localStorage.setItem(STORAGE_KEY, JSON.stringify(st));
  },[pageIndex,selections,checked,submitted,timeLeft]);

  useEffect(()=>{
    if(!running) return;

    timerRef.current = setInterval(()=>{
      setTimeLeft(t=>{
        if(t<=1){
          clearInterval(timerRef.current);
          handleTimeout();
          return 0;
        }
        return t-1;
      });
    },1000);

    return ()=> clearInterval(timerRef.current);
  },[pageIndex,running]);

  const totalQuestions = norm.length;
  const totalPages = Math.ceil(totalQuestions / itemsPerPage);

  function handleSelect(qIndex, option){
    setSelections(prev => ({...prev, [qIndex]:option}));
    setChecked(prev => ({...prev, [qIndex]: option === norm[qIndex].answer}));
  }

  function gotoPage(idx){
    if(idx<0||idx>=totalPages) return;
    setAnimateKey(k=>k+1);
    setPageIndex(idx);
    setTimeLeft(perQuestionTime);
    setRunning(true);
  }

  function handleTimeout(){
    const idx = pageIndex;
    if(selections[idx] === undefined){
      setChecked(prev => ({...prev, [idx]:false}));
    }
    if(pageIndex < totalPages-1) gotoPage(pageIndex+1);
    else setSubmitted(true);
  }

  function handleSubmitQuiz(){
    setSubmitted(true);
    setRunning(false);
    clearInterval(timerRef.current);
  }

  function resetQuiz(){
    setSelections({});
    setChecked({});
    setPageIndex(0);
    setSubmitted(false);
    setRunning(true);
    setTimeLeft(perQuestionTime);
    localStorage.removeItem(STORAGE_KEY);
  }

  const score = (() => {
    let correct=0;
    for(let i=0;i<totalQuestions;i++){
      if(checked[i]) correct++;
    }
    return {correct, total:totalQuestions, percent: Math.round(correct/totalQuestions*100)};
  })();

  // FIXED: Memoize the options so they don’t reshuffle
  const memoizedOptions = useMemo(() => {
    return norm.map(q => generateMCQ(q.answer));
  }, [norm]);


  return (
    <div>
      <h3>Question {pageIndex+1}/{totalPages}</h3>
      <p>{norm[pageIndex].question}</p>

      {memoizedOptions[pageIndex].map((op, i)=>(
        <label key={i}>
          <input
            type="radio"
            name={`q${pageIndex}`}
            checked={selections[pageIndex] === op}
            onChange={()=>handleSelect(pageIndex, op)}
          />
          {op}
        </label>
      ))}

      <div style={{marginTop:10}}>
        <button disabled={pageIndex===0} onClick={()=>gotoPage(pageIndex-1)}>Prev</button>
        <button disabled={pageIndex===totalPages-1} onClick={()=>gotoPage(pageIndex+1)}>Next</button>
        <button onClick={handleSubmitQuiz}>Submit</button>
        <button onClick={resetQuiz}>Reset</button>
      </div>

      {submitted && (
        <div>
          <h3>Results</h3>
          <p>Score: {score.correct}/{score.total} ({score.percent}%)</p>
        </div>
      )}
    </div>
  );
}
